use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

sub extract_info {
    my ($pdf_file) = @_;

    # Ouvrir le fichier PDF
    my $pdf = PDF::API2->open($pdf_file);

    # Obtenir le texte du PDF
    my $text = $pdf->text;

    # Récupérer les informations spécifiques
    my $author = $text->match(/Author: (.+)/);
    my $date = $text->match(/Date: (.+)/);
    my $table = $text->table;

    return {
        author => defined $author ? $author : 'Unknown',
        date => defined $date ? $date : 'Unknown',
        table => defined $table ? $table : 'No table found',
    };
}

# Utiliser la fonction
my $pdf_file = 'exemple.pdf';
my $info = extract_info($pdf_file);

print "Author: $info->{author}\n";
print "Date: $info->{date}\n";
print "Table: $info->{table}\n";
